namespace sv_8662c498bd644c7da0a51a39c0f21c7e.Services;

public sealed class WarehouseStateService
{
    public static readonly IReadOnlyList<(string Id, string Name)> AvailableWarehouses =
    [
        ("WH-A", "Warehouse A"),
        ("WH-B", "Warehouse B"),
        ("WH-C", "Warehouse C"),
    ];

    private string _currentWarehouseId = AvailableWarehouses[0].Id;

    public string CurrentWarehouseId => _currentWarehouseId;

    public string CurrentWarehouseName =>
        AvailableWarehouses.FirstOrDefault(w => w.Id == _currentWarehouseId).Name
        ?? _currentWarehouseId;

    public event Action? OnChange;

    public void SetWarehouse(string warehouseId)
    {
        if (_currentWarehouseId == warehouseId) return;
        _currentWarehouseId = warehouseId;
        OnChange?.Invoke();
    }
}

namespace sv_8662c498bd644c7da0a51a39c0f21c7e.Services;

/// <summary>
/// Scoped service that polls for low-stock alerts in the currently selected warehouse.
/// Each Blazor circuit gets its own instance, so users see independent data.
/// </summary>
public sealed class InventoryAlertService : IDisposable
{
    private readonly WarehouseStateService _warehouseState;
    private PeriodicTimer? _timer;
    private CancellationTokenSource? _cts;
    private int _subscriberCount;
    private readonly Lock _lock = new();

    public int LatestLowStockCount { get; private set; }

    /// <summary>
    /// Raised on the thread-pool when new alert data arrives.
    /// Subscribers must call InvokeAsync/StateHasChanged on the UI sync context.
    /// </summary>
    public event Func<Task>? OnAlertCountChanged;

    public InventoryAlertService(WarehouseStateService warehouseState)
    {
        _warehouseState = warehouseState;
    }

    /// <summary>Simulates a database query returning a random low-stock count (0–15).</summary>
    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        return Task.FromResult(Random.Shared.Next(0, 16));
    }

    /// <summary>
    /// Register interest in polling. Polling starts when the first subscriber calls this
    /// and stops when every subscriber calls <see cref="StopPolling"/>.
    /// </summary>
    public void StartPolling()
    {
        lock (_lock)
        {
            _subscriberCount++;
            if (_subscriberCount == 1)
            {
                _cts = new CancellationTokenSource();
                _timer = new PeriodicTimer(TimeSpan.FromSeconds(10));
                _ = PollLoopAsync(_cts.Token);
            }
        }
    }

    public void StopPolling()
    {
        lock (_lock)
        {
            _subscriberCount = Math.Max(0, _subscriberCount - 1);
            if (_subscriberCount == 0)
            {
                _cts?.Cancel();
                _timer?.Dispose();
                _timer = null;
                _cts?.Dispose();
                _cts = null;
            }
        }
    }

    /// <summary>
    /// Manually trigger a refresh (e.g. after a warehouse change).
    /// </summary>
    public async Task RefreshAsync()
    {
        LatestLowStockCount = await GetLowStockCountAsync(_warehouseState.CurrentWarehouseId);
        await NotifySubscribersAsync();
    }

    private async Task PollLoopAsync(CancellationToken ct)
    {
        // Fire immediately on start so subscribers get data right away.
        await RefreshAsync();

        while (!ct.IsCancellationRequested)
        {
            try
            {
                if (_timer is null || !await _timer.WaitForNextTickAsync(ct))
                    break;
            }
            catch (OperationCanceledException)
            {
                break;
            }

            LatestLowStockCount = await GetLowStockCountAsync(_warehouseState.CurrentWarehouseId);
            await NotifySubscribersAsync();
        }
    }

    private async Task NotifySubscribersAsync()
    {
        if (OnAlertCountChanged is not null)
        {
            await OnAlertCountChanged.Invoke();
        }
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _timer?.Dispose();
        _cts?.Dispose();
    }
}

