﻿@page "/"
@using sv_8662c498bd644c7da0a51a39c0f21c7e.Services
@rendermode InteractiveServer
@inject WarehouseStateService WarehouseState
@inject InventoryAlertService AlertService
@implements IDisposable

<PageTitle>Dashboard</PageTitle>

<h1>Warehouse Dashboard</h1>

<div class="card mb-4">
    <div class="card-body">
        <h5 class="card-title">Current Warehouse</h5>
        <p class="card-text fs-4">
            <strong>@WarehouseState.CurrentWarehouseName</strong>
            <span class="text-muted">(@WarehouseState.CurrentWarehouseId)</span>
        </p>
    </div>
</div>

<div class="card mb-4">
    <div class="card-body">
        <h5 class="card-title">Low-Stock Alerts</h5>
        <p class="card-text">
            @if (AlertService.LatestLowStockCount > 0)
            {
                <span class="badge bg-danger fs-5">@AlertService.LatestLowStockCount items below minimum level</span>
            }
            else
            {
                <span class="badge bg-success fs-5">All stock levels OK</span>
            }
        </p>
        <p class="text-muted"><small>Refreshes every 10 seconds while this page is open.</small></p>
    </div>
</div>

@code {
    protected override void OnInitialized()
    {
        WarehouseState.OnChange += StateHasChanged;
        AlertService.OnAlertCountChanged += OnAlertDataChanged;
        AlertService.StartPolling();
    }

    private async Task OnAlertDataChanged()
    {
        await InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        AlertService.StopPolling();
        AlertService.OnAlertCountChanged -= OnAlertDataChanged;
        WarehouseState.OnChange -= StateHasChanged;
    }
}

